## Streaming Example

Example with streaming API integration:

```tsx
import {useState} from 'react';
import {ChatContainer} from '@gravity-ui/aikit';
import type {ChatStatus, TMessage, TSubmitData} from '@gravity-ui/aikit';

function App() {
  const [messages, setMessages] = useState<TMessage[]>([]);
  const [status, setStatus] = useState<ChatStatus>('ready');
  const [controller, setController] = useState<AbortController | null>(null);

  const handleSendMessage = async (data: TSubmitData) => {
    // Add user message
    const userMessage: TMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: data.content,
    };
    setMessages((prev) => [...prev, userMessage]);

    // Start streaming
    setStatus('streaming');
    const abortController = new AbortController();
    setController(abortController);

    try {
      const response = await fetch('/api/chat/stream', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({message: data.content}),
        signal: abortController.signal,
      });

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      let assistantMessage: TMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: '',
      };

      setMessages((prev) => [...prev, assistantMessage]);

      while (true) {
        const {done, value} = await reader!.read();
        if (done) break;

        const chunk = decoder.decode(value);
        assistantMessage.content += chunk;

        setMessages((prev) =>
          prev.map((msg) => (msg.id === assistantMessage.id ? {...assistantMessage} : msg)),
        );
      }
    } catch (error) {
      if (error.name !== 'AbortError') {
        console.error('Streaming error:', error);
      }
    } finally {
      setStatus('ready');
      setController(null);
    }
  };

  const handleCancel = async () => {
    controller?.abort();
    setStatus('ready');
  };

  return (
    <ChatContainer
      messages={messages}
      onSendMessage={handleSendMessage}
      onCancel={handleCancel}
      status={status}
    />
  );
}
```

