  const [open, setOpen] = useState(false);
  const anchorRef = useRef<HTMLButtonElement>(null);

  return (
    <>
      <ActionTooltip title="Chat History">
        <Button
          ref={anchorRef}
          view="flat"
          size="m"
          onClick={() => setOpen(!open)}
        >
          <Icon data={ClockArrowRotateLeft} size={16} />
