## Using Layers

```typescript
import { Graph } from "@/graph";
import { NewBlockLayer } from "@/components/canvas/layers/newBlockLayer";
import { ConnectionLayer } from "@/components/canvas/layers/connectionLayer";

// Attach when creating a graph
const graph = new Graph({
  layers: [
    [NewBlockLayer, { ghostBackground: "rgba(0, 0, 255, 0.3)" }],
    [ConnectionLayer, {}]
  ]
});

// Or add dynamically
const newBlockLayer = graph.addLayer(NewBlockLayer, { ghostBackground: "rgba(0, 0, 255, 0.3)" });
```

## HTML Rendering in Layers

The Layer class can create both Canvas and HTML elements for rendering:

```typescript
// Example of Layer creation with both Canvas and HTML elements
constructor(props: LayerProps) {
  super({
    canvas: {
      zIndex: 2,
      respectPixelRatio: true,
      classNames: ["no-user-select"],
    },
    html: {
      zIndex: 3,
      classNames: ["no-user-select"],
      transformByCameraPosition: true, // This enables HTML rendering with camera transformation
    },
    ...props,
  });
}
```

### HTML Layer Configuration

- **There is no dedicated "HTMLLayer" class**. Instead, HTML rendering is handled by setting the `html` property in the Layer constructor options.
- The `transformByCameraPosition: true` option is crucial for HTML elements that need to move with the camera.
- When this option is set, the layer adds the "layer-with-camera" class to the HTML element and subscribes to camera state changes.

### Camera Transformation

- HTML elements with `transformByCameraPosition: true` are transformed using a matrix transform based on camera state:
```typescript
this.html.style.transform = `matrix(${camera.scale}, 0, 0, ${camera.scale}, ${camera.x}, ${camera.y})`;
```
- This transformation is applied directly in the `afterInit()` method when the `transformByCameraPosition` option is set to `true`.
- **IMPORTANT**: The camera state subscription is set up in the `afterInit()` method to ensure it's properly reestablished when a layer is reattached.

### React Integration

- React components are rendered into the HTML element of the GraphLayer using `createPortal` in `GraphCanvas.tsx`.
- The BlocksList component renders React blocks only when the camera is at the detailed zoom level.

## Creating Custom Layers

### Basic Structure

Custom layers should extend the base `Layer` class (`src/services/Layer.ts`). This class provides the core functionality for managing Canvas and HTML elements within the graph's rendering pipeline.

```typescript
import { Layer, LayerContext, LayerProps, TGraphColors, TGraphConstants } from "@/services/Layer";
import { ICamera } from "@/services/camera/CameraService";
import { Graph } from "@/graph";

// Define custom properties for your layer, extending the base LayerProps
interface MyLayerProps extends LayerProps {
  customOption?: string;
  gridColor?: string;
}

// Optionally extend the LayerContext if your layer needs additional context
interface MyLayerContext extends LayerContext {
  // Add specific context properties here
}

// Define the Layer, specifying Props and optionally Context
export class MyLayer extends Layer<MyLayerProps, MyLayerContext> {
  constructor(props: MyLayerProps) {
    // Call the base constructor, passing props and potentially overriding default layer settings
    super({
      // Canvas element configuration (optional)
      canvas: {
        zIndex: 10,
        classNames: ["my-layer-canvas"],
        respectPixelRatio: true, // Default: true. Set to false to disable DPR scaling.
        transformByCameraPosition: true // Default: false. Set to true to automatically apply camera transform.
      },
      // HTML element configuration (optional)
      html: {
        zIndex: 11,
        classNames: ["my-layer-html"],
        transformByCameraPosition: true // Default: false. Set to true to apply camera transform via CSS.
      },
      ...props // Pass remaining props, including required `graph` and `camera`
    });

    // --- Context Setup ---
    // Base context (graph, camera, constants, colors, layer) is set by the super constructor.
    // You need to add context specific to the elements created by this layer.
    // It's recommended to do this in `afterInit` when elements are guaranteed to exist.
  }

  // `afterInit` is called after the layer's elements (canvas/html) are created and attached.
  protected afterInit() {
    // Subscribe to events here
    this.onGraphEvent("camera-change", this.performRender);
    // Add other event listeners (e.g., to this.getHTML() or this.getCanvas())
    super.afterInit();
  }

  // --- Rendering --- 
  // This method is called automatically when performRender is invoked (e.g., on camera change).
  protected render() {
    // Check if context is fully initialized
    if (!this.context.ctx || !this.context.graphCanvas) {
      return; 
    }

    // Reset transformations and clear canvas
    this.resetTransform(); // Applies camera transform if transformByCameraPosition=true, respects DPR

    const { ctx, camera, constants, colors } = this.context;
    const { scale, x, y } = camera.getCameraState();

    // --- Custom Rendering Logic --- 
    // Draw using world coordinates. `resetTransform` handles the necessary scaling and translation.
    ctx.fillStyle = this.props.gridColor || colors.canvas.gridColor; // Example using props/colors
    ctx.fillRect(10, 10, 50, 50); // Draws a rectangle at world coordinates (10, 10)

    // Example: Apply additional transform relative to the camera
    // this.applyTransform(worldX, worldY, worldScale); // Respects DPR
  }

  // --- Cleanup --- 
  // Called when the layer is removed from the graph.
  protected unmount(): void {
    // Call super.unmount() to trigger the AbortController's abort method
    // which automatically removes all event listeners
    super.unmount();
    // No need to manually remove event listeners as they are automatically
    // cleaned up by the AbortController
  }
}
```

### Handling Transformations and Device Pixel Ratio (DPR)

The `Layer` class provides tools to handle rendering correctly with camera transformations and on high-resolution (HiDPI) displays.

- **`respectPixelRatio`** (`LayerProps.canvas.respectPixelRatio`, default: `true`):
    - When `true`, the canvas dimensions are automatically scaled by the device pixel ratio (`window.devicePixelRatio`).
    - The `resetTransform()` and `applyTransform()` methods automatically account for this scaling, so you can draw using world coordinates without manual DPR calculation.
    - Set to `false` only if you need explicit manual control over pixel scaling.

- **`transformByCameraPosition`** (`LayerProps.canvas.transformByCameraPosition` / `LayerProps.html.transformByCameraPosition`, default: `false`):
    - **For Canvas:** When `true`, the `resetTransform()` method automatically applies the current camera translation (`x`, `y`) and `scale` to the canvas context (`ctx`). This means your subsequent drawing operations in the `render` method should use world coordinates.
    - **For HTML:** When `true`, the HTML element gets the `layer-with-camera` class, and its CSS `transform: matrix(...)` is automatically updated on camera changes to match the camera's position and scale.

- **`resetTransform()`**:
    - Call this at the beginning of your canvas `render` method.
    - It resets the canvas context's transform to the identity matrix.
    - It clears the entire canvas (`clearRect`).
    - If `transformByCameraPosition` is `true` for the canvas, it applies the current camera transform (`scale`, `x`, `y`), automatically accounting for DPR if `respectPixelRatio` is `true`.

- **`applyTransform(x, y, scale, respectPixelRatioOverride)`**:
    - Applies an *additional* transformation to the canvas context, relative to the current transform (which includes the camera transform if set by `resetTransform`).
    - Useful for drawing elements at specific world positions/scales relative to the base camera view.
    - It automatically accounts for DPR based on the layer's `respectPixelRatio` setting unless overridden by the optional fourth argument.

- **`getDRP()`**:
    - Returns the device pixel ratio value that the layer is currently using (respecting the `respectPixelRatio` flag).
    - Use this only if you need the DPR value for complex manual calculations, usually unnecessary when using `resetTransform` and `applyTransform`.

**In summary:** For most canvas layers, set `respectPixelRatio: true` and `transformByCameraPosition: true`, call `resetTransform()` at the start of `render`, and draw using world coordinates. Use `applyTransform` for specific relative positioning if needed.

### Built-in CSS Classes

The library provides several built-in CSS classes that can be used with layers:

- **no-pointer-events**: Disables pointer events on the layer, making it transparent to mouse interactions. Useful for layers that only render visual elements but shouldn't capture mouse events.

  ```typescript
  canvas: {
    zIndex: 4,
    classNames: ["no-pointer-events"]
  }
  ```

- **no-user-select**: Prevents text selection on the layer. Useful for layers with text content that shouldn't be selectable.

  ```typescript
  html: {
    zIndex: 5,
    classNames: ["no-user-select"]
  }
  ```

- **layer-with-camera**: Automatically applied when `transformByCameraPosition: true` is set. Makes the HTML layer transform according to camera movements.

You can combine these classes as needed:

```typescript
html: {
  zIndex: 3,
  classNames: ["my-custom-layer", "no-pointer-events", "no-user-select"]
}
```

### Layer Interaction

```typescript
import { ConnectionLayer } from "@/components/canvas/layers/connectionLayer";

// Access another layer
const connectionLayer = this.context.graph.layers.find(layer => layer instanceof ConnectionLayer);

// Use events
this.context.graph.on("connection-created", (event) => {
  // React to connection creation
});
```

### Event Handling with Wrapper Methods

The Layer class provides convenient wrapper methods for subscribing to events using `AbortController`. This ensures that all event handlers are automatically removed when the layer is unmounted, preventing memory leaks and redundant subscriptions.

**Main subscription methods:**
- `onGraphEvent` — for graph events
- `onHtmlEvent` — for HTML element events
- `onCanvasEvent` — for canvas element events
- `onRootEvent` — for root element events

> It is recommended to set up all subscriptions in the `afterInit()` method so they are properly re-established when the layer is remounted.

**Example:**
```typescript
protected afterInit() {
  this.onGraphEvent("camera-change", this.handleCameraChange);
  this.onCanvasEvent("mousedown", this.handleMouseDown);
  super.afterInit();
}
```

When the layer is unmounted, all handlers are automatically removed.

### Manual Event Subscriptions

While the wrapper methods (`onGraphEvent`, `onHtmlEvent`, `onCanvasEvent`, `onRootEvent`) are recommended, you can also manually create event subscriptions using the layer's AbortController:

```typescript
export class MyCustomLayer extends Layer<MyLayerProps> {
  private unsubscribeFunctions: Array<() => void> = [];

  constructor(props: MyLayerProps) {
    super(props);
    // Initialize properties, but DO NOT register event listeners here
  }

  protected afterInit(): void {
    // Option 1: Manual subscription using the layer's AbortController
    // This will be automatically cleaned up when the layer is unmounted
    this.canvas.addEventListener("mousedown", this.handleMouseDown, {
      signal: this.eventAbortController.signal
    });

    // Option 2: Manual subscription to graph events with AbortController
    this.props.graph.on("camera-change", this.performRender, {
      signal: this.eventAbortController.signal
    });

    // Option 3: Manual subscription without AbortController
    // In this case, you must handle unsubscription manually
    const unsubscribe = this.props.graph.on("block-change", this.handleBlockChange);

    // Store the unsubscribe function for later use
    this.unsubscribeFunctions.push(unsubscribe);

    // Always call super.afterInit() at the end
    super.afterInit();
  }

  protected unmount(): void {
    // Call super.unmount() to trigger the AbortController's abort method
    // This will clean up all event listeners registered with the AbortController
    super.unmount();

    // Manually call any stored unsubscribe functions
    // This is only needed for event listeners that weren't registered with the AbortController
    this.unsubscribeFunctions.forEach(unsubscribe => unsubscribe());
    this.unsubscribeFunctions = [];
  }

  private handleMouseDown = (event: MouseEvent) => {
    // Handle mouse down event
  };

  private performRender = () => {
    // Handle camera change event
  };

  private handleBlockChange = () => {
    // Handle block change event
  };
}
```

Using the wrapper methods is generally preferred as they provide automatic cleanup and error checking, but manual subscriptions give you more flexibility when needed.

### Example: Grid Layer

```typescript
import { Layer } from "@/services/Layer";
import { CameraService } from "@/services/camera/CameraService";

interface GridLayerProps {
  camera: CameraService;
  graph: any;
}

export class GridLayer extends Layer<GridLayerProps> {

  protected ctx: CanvasRenderingContext2D;

  constructor(props: GridLayerProps) {
    super({
      canvas: { zIndex: 1, classNames: ["grid-layer"] },
      ...props
    });

    this.ctx = this.getCanvas().getContext("2d");

    this.performRender = this.performRender.bind(this);
  }

  /**
   * Called after initialization and when the layer is reattached.
   * This is where we set up event subscriptions to ensure they work properly
   * after the layer is unmounted and reattached.
   */
  protected afterInit(): void {
    // Use the onGraphEvent wrapper method for automatic cleanup
    this.onGraphEvent("camera-change", this.performRender);

    // Call parent afterInit to ensure proper initialization
    super.afterInit();
  }

  protected render() {
    const { ctx, camera } = this.context;
    const { width, height, scale, x, y } = camera.getCameraState();

    ctx.clearRect(0, 0, width, height);

    // Draw grid
    ctx.beginPath();
    ctx.strokeStyle = "rgba(0, 0, 0, 0.1)";

    const gridSize = 20 * scale;
    const offsetX = x % gridSize;
    const offsetY = y % gridSize;

    for (let i = offsetX; i < width; i += gridSize) {
      ctx.moveTo(i, 0);
      ctx.lineTo(i, height);
    }

    for (let i = offsetY; i < height; i += gridSize) {
      ctx.moveTo(0, i);
      ctx.lineTo(width, i);
    }

    ctx.stroke();
  }

  protected unmount(): void {
    // Call super.unmount() to trigger the AbortController's abort method
    super.unmount();
    // No need to manually remove event listeners
  }
}

```

## Subscribing to signals with onSignal

For reactive data (such as signals from @preact/signals-core), the Layer class provides a convenient onSignal method. It allows you to subscribe to a signal and automatically unsubscribe when the layer is unmounted (unmount) or when the AbortController is triggered:

```typescript
protected onSignal<T>(
  signal: { subscribe: (handler: (value: T) => void) => () => void },
  handler: (value: T) => void
): () => void
```

- **signal** — an object with a subscribe method that returns an unsubscribe function (for example, a signal from @preact/signals-core)
- **handler** — a function called when the signal value changes
- **returns** an unsubscribe function, which is usually not needed to call manually

### Example usage

```typescript
protected afterInit() {
  // Subscribe to a signal with automatic cleanup on layer unmount
  this.onSignal(this.props.graph.rootStore.blocksList.$blocks, (blocks) => {
    this.shouldUpdateChildren = true;
    this.performRender();
  });
  super.afterInit();
}
```

> Unsubscription will happen automatically when the internal AbortController of the layer is aborted (for example, on detachLayer or destroy).

# Camera Service

This document describes the camera model in @gravity-ui/graph: how it transforms coordinates, how pan/zoom work, which API is available, and when to use optional viewport insets.

## Core ideas

- Camera defines a transform from world (graph) space to screen (canvas) space.
- Camera state consists of screen-space translation `(x, y)`, `scale`, and canvas dimensions `(width, height)`.
- Derived camera-space viewport (`relativeX/Y/Width/Height`) is computed from the full canvas size and is used in hit-testing, visibility checks, and canvas rendering.

## State

```ts
export type TCameraState = {
  x: number;              // screen-space camera X (translation)
  y: number;              // screen-space camera Y (translation)
  width: number;          // canvas width in CSS pixels
  height: number;         // canvas height in CSS pixels
  scale: number;          // zoom scale
  scaleMin: number;
  scaleMax: number;
  // Camera-space viewport derived from full canvas (ignores insets)
  relativeX: number;
  relativeY: number;
  relativeWidth: number;
  relativeHeight: number;
  // Optional UI focus area (screen-space paddings inside canvas)
  viewportInsets: { left: number; right: number; top: number; bottom: number };
  // Auto-panning mode enabled state
  autoPanningEnabled: boolean;
};
```

## Coordinate conversions

- `getRelative(n)` / `getRelativeXY(x, y)` – screen → camera space.
- `getAbsolute(n)` / `getAbsoluteXY(x, y)` – camera → screen space.
- `applyToPoint(x, y)` / `applyToRect(x, y, w, h)` – fast helpers to apply camera transform.

## Camera control

- `set(newState)` – update camera state (emits `camera-change`).
- `resize({ width, height })` – update canvas size preserving center.
- `move(dx, dy)` – pan.
- `zoom(x, y, scale)` – zoom anchored to a screen-space point `(x, y)`.
- `getCameraRect()` – screen-space camera rect.
- `getCameraScale()` – scale value.
- `getCameraBlockScaleLevel(scale?)` – qualitative zoom tiers for switching rendering modes.

### Mouse wheel behavior

Mouse wheel interactions can be configured to either zoom the graph or scroll it.

**Configuration:**
```ts
const graph = new Graph(canvas, {
  constants: {
    camera: {
      MOUSE_WHEEL_BEHAVIOR: "zoom" // "zoom" | "scroll" (default: "zoom")
    }
  }
});
```

**Behavior modes:**
- `"zoom"` (default) – Mouse wheel zooms the graph in/out at the cursor position.
- `"scroll"` – Mouse wheel scrolls the graph vertically by default, or horizontally when Shift key is pressed.

**Scroll direction:**
- Default: Vertical scrolling (up/down along Y axis)
- With Shift: Horizontal scrolling (left/right along X axis)

**Important notes:**
- This configuration only affects mouse wheel behavior.
- Scroll direction switching with Shift is an environment-dependent behavior according to [W3C UI Events specification](https://w3c.github.io/uievents/#events-wheelevents).
- Different browsers and operating systems may handle Shift+wheel differently.
- Trackpad gestures remain unchanged and use their native behavior:
  - Pinch to zoom
  - Two-finger swipe to scroll in any direction
- Settings can be updated at runtime using `graph.setConstants()`.

**Example:**
```ts
// Configure mouse wheel to scroll instead of zooming
graph.setConstants({
  camera: {
    MOUSE_WHEEL_BEHAVIOR: "scroll"
  }
});

// Switch back to zoom mode
graph.setConstants({
  camera: {
    MOUSE_WHEEL_BEHAVIOR: "zoom"
  }
});
```

### Auto-panning

Auto-panning automatically moves the camera when the cursor is near viewport edges during drag operations. This feature is built into the camera system and activates automatically for block dragging, area selection, connection creation, and block duplication.

- `enableAutoPanning()` – enable auto-panning mode.
- `disableAutoPanning()` – disable auto-panning mode.
- `isAutoPanningEnabled()` – check if auto-panning is currently enabled.

**How it works:**
- When enabled, the camera monitors mouse position relative to viewport edges (respecting `viewportInsets`).
- If the cursor is within the threshold distance from any edge, the camera pans in the corresponding direction.

**Configuration:**
Auto-panning behavior can be customized via configuration:
```ts
const graph = new Graph(canvas, {
  constants: {
    camera: {
      AUTO_PAN_THRESHOLD: 50,  // pixels from edge to activate (default: 50)
      AUTO_PAN_SPEED: 10,      // base pixels per frame (default: 10)
    }
  }
});
```

**Example:**
```ts
// Enable auto-panning (typically called at drag start)
graph.cameraService.enableAutoPanning();

// ... user drags something near the edge, camera auto-pans ...

// Disable auto-panning (typically called at drag end)
graph.cameraService.disableAutoPanning();
```

## Viewports and fitting

- `getRelativeViewportRect(options?)`
  - Default: returns full camera-space viewport (ignores insets).
  - `{ respectInsets: true }`: returns camera-space viewport bounded by insets (visible area).
- `getVisibleCameraRect()` – screen-space visible rect that respects insets.
- `getScaleRelativeDimensions(width, height, { respectInsets })` – compute scale to fit a target rect.
- `getXYRelativeCenterDimensions(rect, scale, { respectInsets })` – compute camera `(x, y)` so the target rect is centered at given scale.

## Rendering, hit-testing, and HTML view

- Canvas rendering and hit-testing use the full camera-space viewport (`relative*`) for correctness and performance.
- HTML/React view switches at defined zoom tiers (`getCameraBlockScaleLevel`), which depend on `scale` independent of insets.

## Events

- `camera-change` – emitted on any camera state update (`set`, `move`, `resize`, `zoom`, etc.).

## Viewport insets (optional focus)

`viewportInsets` let the UI define a static focus frame inside the canvas (e.g., when a side panel overlays part of the canvas). Insets live in screen space and do not change the core camera geometry. Use them to modify user-visible centering/fitting only.

- Update: `setViewportInsets({ left, right, top, bottom }, { maintain?: "center" })`.
  - When `maintain: "center"` is passed, the same world point remains under the visible center after insets change.
  - If the second argument is omitted, the camera position is not adjusted to preserve the center.
- Read: `getViewportInsets()`.
- Fitting/centering with focus: pass `{ respectInsets: true }` to `getScaleRelativeDimensions` and `getXYRelativeCenterDimensions` (used by `zoomToRect`, `zoomToViewPort`).
- Ignored by low-level systems: background rendering and hit-test continue to use full viewport.

### Examples

```ts
// Side drawer overlays 300px on the left
camera.setViewportInsets({ left: 300 });
graph.api.zoomToViewPort({ padding: 24 }); // fits into visible area

// Remove focus
camera.setViewportInsets({ left: 0, right: 0, top: 0, bottom: 0 });

// Resize focus frame while keeping the visible center anchored to the same world point
camera.setViewportInsets({ left: 200, right: 100 }, { maintain: "center" });
```

For an interactive demo, see `stories/examples/viewportInsets/viewportInsets.stories.tsx`.

# Component Lifecycle

This document provides an in-depth explanation of the component lifecycle in the rendering system, focusing on both the CoreComponent and Component classes.

> **Note:** This document is part of a series on the rendering architecture. See also [Rendering Mechanism](../rendering/rendering-mechanism.md), [Scheduler System](./scheduler-system.md), and [Component Rendering Integration](./component-rendering-lifecycle.md).

## Overview

The component lifecycle consists of five main phases that each component goes through from creation to removal:

| Phase | Description |
|-------|-------------|
| Initialization | Component creation and setup |
| Mounting | First addition to the component tree |
| Updating | Processing state/props changes and rendering |
| Children Management | Creating and updating child components |
| Unmounting | Cleanup and removal from the tree |

## Lifecycle Phases

### 1. Initialization Phase

```mermaid
flowchart TD
    A[new Component/CoreComponent] --> B[constructor]
    B --> C[Initialize private data]
    C --> D[Set up Tree node]
    D --> E[Initialize props/state]
    E --> F[Component is ready]
```

During initialization:
1. The component's constructor sets up private properties
2. The component is registered in the Tree structure
3. Initial props and state are established

### 2. CoreComponent Lifecycle

The CoreComponent provides the foundation with three main methods:

| Method | Purpose | When Called |
|--------|---------|-------------|
| `iterate()` | Manages the update cycle | Each frame |
| `updateChildren()` | Defines and updates child components | During children update |
| `render()` | Handles visual rendering | During render phase |

> **Note:** For details on how these methods interact with the rendering pipeline, see [Rendering Mechanism](../rendering/rendering-mechanism.md).

### 3. Component Lifecycle Methods

The Component class extends CoreComponent with additional lifecycle hooks:

#### Method Sequence

During component iteration, methods are called in this order:

1. First Iteration Only:
   - `willMount()`

2. Every Iteration:
   ```mermaid
   flowchart TD
       A[checkData] --> B[willIterate]
       B --> C{shouldRender?}
       C -->|Yes| D[willRender]
       D --> E[render]
       E --> F[didRender]
       C -->|No| G[willNotRender]
       G --> H{shouldUpdateChildren?}
       F --> H
       H -->|Yes| I[willUpdateChildren]
       I --> J[updateChildren]
       J --> K[didUpdateChildren]
       H -->|No| L[didIterate]
       K --> L
   ```

### 4. State and Props Management

When state or props change:

| Step | Action | Method |
|------|--------|---------|
| 1 | Changes called | `setState()` or `setProps()` |
| 2 | Changes buffered | Stored in `__data` |
| 3 | Update scheduled | `performRender()` |
| 4 | Changes processed | `checkData()` |
| 5 | Callbacks triggered | `propsChanged()` or `stateChanged()` |
| 6 | Render evaluated | Based on `shouldRender` flag |

### 5. Control Flags

Components use several boolean flags to control their behavior:

| Flag | Purpose | Default Value |
|------|---------|---------------|
| `firstIterate` | Tracks first iteration | `true` |
| `firstRender` | Tracks first render | `true` |
| `firstUpdateChildren` | Tracks first children update | `true` |
| `shouldRender` | Controls render() call | `true` |
| `shouldUpdateChildren` | Controls children updates | `true` |
| `shouldRenderChildren` | Controls children rendering | `true` |

## Examples

### Basic Component

```typescript
import { Component } from "@gravity-ui/graph";

class MyComponent extends Component {
  protected willMount() {
    // Initialize, similar to constructor but guaranteed to run before first render
    this.setState({ counter: 0 });
  }

  protected render() {
    // Render logic
    console.log('Rendering with counter:', this.state.counter);
  }

  public increment() {
    this.setState({ counter: this.state.counter + 1 });
  }
}
```

### Component with Children

```typescript
import { Component } from "@gravity-ui/graph";

class ParentComponent extends Component {
  protected updateChildren() {
    return [
      ChildComponent.create({ value: this.state.value }, { key: 'child1' }),
      AnotherChild.create({ data: this.props.data }, { key: 'child2' })
    ];
  }

  protected willUpdateChildren() {
    console.log('About to update children');
  }

  protected didUpdateChildren() {
    console.log('Children updated');
  }
}
```

## Best Practices

### Performance Optimization

1. Control rendering with lifecycle flags:
   ```typescript
   protected propsChanged(nextProps) {
     // Only render if relevant props have changed
     this.shouldRender = nextProps.value !== this.props.value;
   }
   ```

2. Batch state updates:
   ```typescript
   // Instead of multiple setState calls:
   // this.setState({ value: 1 });
   // this.setState({ count: 2 });

   // Batch updates in one call:
   this.setState({ value: 1, count: 2 });
   ```

> **Important:** Always clean up resources in the `unmount()` method to prevent memory leaks.

# Drag System

The Drag System provides a centralized way to handle drag operations for all graph components. It automatically manages drag lifecycle, autopanning, cursor states, and coordinates movement across multiple selected components.

## Overview

When a user drags components on the graph:
1. **DragService** intercepts the mouse events
2. Collects all selected draggable components
3. Manages the drag lifecycle (start → update → end)
4. Handles autopanning near canvas edges
5. Synchronizes cursor state
6. Delegates actual movement to components via lifecycle methods

### Key Benefits

- **Unified Drag Behavior**: All draggable components use the same drag system
- **Multi-Selection Support**: Drag multiple selected components simultaneously
- **Automatic Autopanning**: Camera moves when dragging near canvas edges
- **Reactive State**: Track drag state for conditional behaviors (e.g., disable snapping)
- **Type Safety**: Full TypeScript support with typed contexts and diffs

## Basic Usage

### Accessing Drag State

The `DragService` exposes a reactive `$state` signal that you can use to track the current drag operation:

```typescript
import { Graph } from "@gravity-ui/graph";

const graph = new Graph(config, container);

// Subscribe to drag state changes
graph.dragService.$state.subscribe((state) => {
  if (state.isDragging) {
    console.log("Dragging", state.components.length, "components");
    console.log("Component types:", [...state.componentTypes]);
    console.log("Is homogeneous:", state.isHomogeneous);
  }
});
```

### Drag State Properties

| Property | Type | Description |
|----------|------|-------------|
| `isDragging` | `boolean` | Whether a drag operation is in progress |
| `components` | `GraphComponent[]` | Components participating in the drag |
| `componentTypes` | `Set<string>` | Set of component type names (constructor names) |
| `isMultiple` | `boolean` | Whether multiple components are being dragged |
| `isHomogeneous` | `boolean` | Whether all components are of the same type |

### Example: Conditional Behavior Based on Drag State

```typescript
// Disable snap-to-grid when dragging heterogeneous components
function shouldSnapToGrid(graph: Graph): boolean {
  const { isDragging, isHomogeneous, componentTypes } = graph.dragService.$state.value;

  // Only snap when dragging blocks of the same type
  if (isDragging && !isHomogeneous) {
    return false;
  }

  // Only snap for Block components
  if (isDragging && !componentTypes.has("Block")) {
    return false;
  }

  return true;
}
```

## Creating Draggable Components

To make a custom `GraphComponent` draggable, override the drag lifecycle methods:

### Step 1: Enable Dragging

Override `isDraggable()` to return `true` when the component should be draggable:

```typescript
import { GraphComponent } from "@gravity-ui/graph";

class MyCustomComponent extends GraphComponent {
  public override isDraggable(): boolean {
    // Draggable when not locked and geometry changes are allowed
    return !this.props.locked && this.canChangeGeometry();
  }
}
```

### Step 2: Handle Drag Start

Override `handleDragStart()` to initialize drag state:

```typescript
import { DragContext } from "@gravity-ui/graph";

class MyCustomComponent extends GraphComponent {
  private initialPosition: { x: number; y: number } | null = null;

  public override handleDragStart(context: DragContext): void {
    // Store initial position for absolute positioning
    this.initialPosition = {
      x: this.state.x,
      y: this.state.y,
    };

    // Emit custom event
    this.context.graph.emit("my-component-drag-start", {
      component: this,
      position: this.initialPosition,
    });
  }
}
```

### Step 3: Handle Drag Updates

Override `handleDrag()` to update component position during drag:

```typescript
import { DragDiff, DragContext } from "@gravity-ui/graph";

class MyCustomComponent extends GraphComponent {
  public override handleDrag(diff: DragDiff, context: DragContext): void {
    if (!this.initialPosition) return;

    // Option 1: Use absolute diff (relative to drag start)
    const newX = this.initialPosition.x + diff.diffX;
    const newY = this.initialPosition.y + diff.diffY;

    // Option 2: Use incremental delta (frame-to-frame movement)
    // const newX = this.state.x + diff.deltaX;
    // const newY = this.state.y + diff.deltaY;

    this.updatePosition(newX, newY);
  }
}
```

### Step 4: Handle Drag End

Override `handleDragEnd()` to finalize the drag operation:

```typescript
import { DragContext } from "@gravity-ui/graph";

class MyCustomComponent extends GraphComponent {
  public override handleDragEnd(context: DragContext): void {
    // Clean up drag state
    this.initialPosition = null;

    // Update hit box for accurate hit testing
    this.updateHitBox(this.state);

    // Emit custom event
    this.context.graph.emit("my-component-drag-end", {
      component: this,
      position: { x: this.state.x, y: this.state.y },
    });
  }
}
```

## DragDiff Reference

The `DragDiff` object provides coordinate information during drag:

| Property | Type | Description |
|----------|------|-------------|
| `startCoords` | `[number, number]` | World coordinates when drag started |
| `prevCoords` | `[number, number]` | World coordinates from previous frame |
| `currentCoords` | `[number, number]` | Current world coordinates |
| `diffX` | `number` | Absolute X displacement from start (`currentCoords[0] - startCoords[0]`) |
| `diffY` | `number` | Absolute Y displacement from start (`currentCoords[1] - startCoords[1]`) |
| `deltaX` | `number` | Incremental X change since last frame (`currentCoords[0] - prevCoords[0]`) |
| `deltaY` | `number` | Incremental Y change since last frame (`currentCoords[1] - prevCoords[1]`) |

### When to Use `diffX/diffY` vs `deltaX/deltaY`

**Use `diffX/diffY` (absolute)** when you need position relative to drag start:
```typescript
// Good for: Restoring to initial position + offset
const newX = this.initialPosition.x + diff.diffX;
const newY = this.initialPosition.y + diff.diffY;
```

**Use `deltaX/deltaY` (incremental)** when you need frame-to-frame movement:
```typescript
// Good for: Accumulating position changes
const newX = this.state.x + diff.deltaX;
const newY = this.state.y + diff.deltaY;
```

## DragContext Reference

The `DragContext` object provides additional information about the drag operation:

| Property | Type | Description |
|----------|------|-------------|
| `sourceEvent` | `MouseEvent` | The native mouse event |
| `startCoords` | `[number, number]` | World coordinates when drag started |
| `prevCoords` | `[number, number]` | World coordinates from previous frame |
| `currentCoords` | `[number, number]` | Current world coordinates |
| `components` | `GraphComponent[]` | All components participating in this drag |

### Example: Coordinated Multi-Component Behavior

```typescript
public override handleDrag(diff: DragDiff, context: DragContext): void {
  // Check if this is a multi-component drag
  if (context.components.length > 1) {
    // Skip individual snapping when dragging multiple items
    this.moveWithoutSnapping(diff.deltaX, diff.deltaY);
  } else {
    // Apply snapping for single item drag
    this.moveWithSnapping(diff.deltaX, diff.deltaY);
  }
}
```

## React Integration

### Reacting to Drag State Changes

```tsx
import { useEffect, useState } from "react";
import { useGraph, DragState } from "@gravity-ui/graph";

function DragIndicator() {
  const { graph } = useGraph();
  const [dragState, setDragState] = useState<DragState | null>(null);

  useEffect(() => {
    if (!graph) return;

    const unsubscribe = graph.dragService.$state.subscribe((state) => {
      setDragState(state);
    });

    return unsubscribe;
  }, [graph]);

  if (!dragState?.isDragging) return null;

  return (
    <div className="drag-indicator">
      Dragging {dragState.components.length} item(s)
      {!dragState.isHomogeneous && " (mixed types)"}
    </div>
  );
}
```

### Disabling UI During Drag

```tsx
function Toolbar() {
  const { graph } = useGraph();
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    if (!graph) return;

    const unsubscribe = graph.dragService.$state.subscribe((state) => {
      setIsDragging(state.isDragging);
    });

    return unsubscribe;
  }, [graph]);

  return (
    <div className="toolbar">
      <button disabled={isDragging}>Add Block</button>
      <button disabled={isDragging}>Delete Selected</button>
    </div>
  );
}
```

## Block Drag Events

The built-in `Block` component emits events during drag operations that you can listen to:

| Event | Description | Payload |
|-------|-------------|---------|
| `block-drag-start` | Fires when block drag starts | `{ nativeEvent, block }` |
| `block-drag` | Fires on each drag frame | `{ nativeEvent, block, x, y }` |
| `block-drag-end` | Fires when block drag ends | `{ nativeEvent, block }` |

### Example: Listening to Block Drag Events

```typescript
graph.on("block-drag-start", (event) => {
  console.log("Block drag started:", event.detail.block.id);
});

graph.on("block-drag", (event) => {
  const { block, x, y } = event.detail;
  console.log(`Block ${block.id} moving to (${x}, ${y})`);

  // Prevent default to cancel the drag
  // event.preventDefault();
});

graph.on("block-drag-end", (event) => {
  console.log("Block drag ended:", event.detail.block.id);
});
```

## Advanced Topics

### Drag Behavior with Selection

The DragService integrates with the SelectionService:

1. **Target in selection**: All selected draggable components move together
2. **Target not in selection**: Only the target component moves

```typescript
// Example: User has blocks A, B, C selected
// - Click and drag block A → A, B, C all move
// - Click and drag block D (not selected) → Only D moves
```

### Autopanning

Autopanning is automatically enabled during drag operations. When the cursor moves near the canvas edges, the camera pans to follow:

```typescript
// Autopanning is managed by DragService
// - Enabled on drag start
// - Disabled on drag end
// - Camera changes trigger position recalculation for smooth movement
```

### Cursor Locking

During drag operations, the cursor is locked to "grabbing":

```typescript
// Cursor management is automatic
// - Locks to "grabbing" on first move
// - Unlocks when drag ends
```

## Complete Example: Custom Draggable Node

```typescript
import {
  GraphComponent,
  DragContext,
  DragDiff,
  TGraphComponentProps,
} from "@gravity-ui/graph";

interface NodeProps extends TGraphComponentProps {
  locked?: boolean;
}

interface NodeState {
  x: number;
  y: number;
  width: number;
  height: number;
}

export class CustomNode extends GraphComponent<NodeProps, NodeState> {
  private dragStartPosition: { x: number; y: number } | null = null;

  public getEntityId(): string {
    return this.props.id;
  }

  // Enable dragging when not locked
  public override isDraggable(): boolean {
    return !this.props.locked;
  }

  // Store initial position on drag start
  public override handleDragStart(context: DragContext): void {
    this.dragStartPosition = {
      x: this.state.x,
      y: this.state.y,
    };

    this.context.graph.emit("custom-node-drag-start", {
      nodeId: this.getEntityId(),
      position: this.dragStartPosition,
    });
  }

  // Update position during drag
  public override handleDrag(diff: DragDiff, context: DragContext): void {
    if (!this.dragStartPosition) return;

    // Use absolute diff for stable positioning
    const newX = this.dragStartPosition.x + diff.diffX;
    const newY = this.dragStartPosition.y + diff.diffY;

    // Apply snapping only for single-item drags
    const shouldSnap = context.components.length === 1;
    const [finalX, finalY] = shouldSnap
      ? this.snapToGrid(newX, newY)
      : [newX, newY];

    this.setState({ x: finalX, y: finalY });
    this.updateHitBox({ ...this.state, x: finalX, y: finalY });
  }

  // Clean up on drag end
  public override handleDragEnd(context: DragContext): void {
    this.context.graph.emit("custom-node-drag-end", {
      nodeId: this.getEntityId(),
      position: { x: this.state.x, y: this.state.y },
    });

    this.dragStartPosition = null;
    this.updateHitBox(this.state);
  }

  private snapToGrid(x: number, y: number): [number, number] {
    const gridSize = 20;
    return [
      Math.round(x / gridSize) * gridSize,
      Math.round(y / gridSize) * gridSize,
    ];
  }

  private updateHitBox(state: NodeState): void {
    this.setHitBox(
      state.x,
      state.y,
      state.x + state.width,
      state.y + state.height
    );
  }

  protected render(): void {
    // Render the node...
  }
}
```

## API Reference

### DragService

| Property/Method | Type | Description |
|----------------|------|-------------|
| `$state` | `Signal<DragState>` | Reactive signal with current drag state |
| `destroy()` | `() => void` | Cleanup method (called automatically on graph unmount) |

### DragState

```typescript
type DragState = {
  isDragging: boolean;
  components: GraphComponent[];
  componentTypes: Set<string>;
  isMultiple: boolean;
  isHomogeneous: boolean;
};
```

### DragContext

```typescript
type DragContext = {
