import {Table, useTable} from '@gravity-ui/table';
import type {ColumnDef, SortingState} from '@gravity-ui/table/tanstack';

type Employee = {
  id: string;
  name: string;
  department: string;
  email: string;
}

const employeeColumns: ColumnDef<Employee>[] = [
  {
    id: 'department',
    header: 'Department',
