}

// Custom sorting function
type User = {
  id: string;
  name: string;
  email: string;
}

const customSortColumns: ColumnDef<User>[] = [
  {
    id: 'name',
    header: 'Name',
    accessorKey: 'name',
    sortingFn: (rowA, rowB) => {
      // Custom sorting logic
      const a = rowA.original.name.toLowerCase();
      const b = rowB.original.name.toLowerCase();
      return a.localeCompare(b);
    },
  },
  {
    id: 'email',
    header: 'Email',
    accessorKey: 'email',
  },
];

const customSortData: User[] = [
  {id: '1', name: 'John Doe', email: 'john@example.com'},
  {id: '2', name: 'Jane Smith', email: 'jane@example.com'},
];

function CustomSorting() {
  const [sorting, setSorting] = React.useState<SortingState>([]);

  const table = useTable({
    data: customSortData,
    columns: customSortColumns,
    enableSorting: true,
    state: {sorting},
    onSortingChange: setSorting,
    getRowId: (row) => row.id,
  });

  return <Table table={table} />;
}

// Server-side sorting
const serverSortColumns: ColumnDef<User>[] = [
  {
    id: 'name',
    header: 'Name',
    accessorKey: 'name',
    enableSorting: true,
  },
  {
    id: 'email',
    header: 'Email',
    accessorKey: 'email',
    enableSorting: true,
  },
];

function ServerSideSorting() {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [data, setData] = React.useState<User[]>([]);

  React.useEffect(() => {
    // Server request with sorting parameters
    const fetchData = async (params: {sortBy?: string; sortOrder?: string}) => {
      const response = await fetch(`/api/users?sortBy=${params.sortBy}&sortOrder=${params.sortOrder}`);
      return response.json();
    };

    fetchData({
      sortBy: sorting[0]?.id,
      sortOrder: sorting[0]?.desc ? 'desc' : 'asc',
    }).then(setData);
  }, [sorting]);

  const table = useTable({
    data,
    columns: serverSortColumns,
    enableSorting: true,
    manualSorting: true, // Server-side sorting
    state: {sorting},
    onSortingChange: setSorting,
    getRowId: (row) => row.id,
  });

  return (
    <Table table={table} />
  );
}
