})
```

## Alternative usage

With parts renderers `generateRenderContent`, `renderHeadContent`, `renderBodyContent` via html streaming:

```js
import express from 'express';
import htmlescape from 'htmlescape';
import {
  generateRenderContent,
  renderHeadContent,
  renderBodyContent,
  createDefaultPlugins,
} from '@gravity-ui/app-layout';

const app = express();

app.get('/', async function (req, res) {
  res.writeHead(200, {
    'Content-Type': 'text/html',
    'Transfer-Encoding': 'chunked',
  });

  const plugins = createDefaultPlugins({layout: {manifest: 'path/to/assets-manifest.json'}});

  const content = generateRenderContent(plugins, {
    title: 'Home page',
  });

  const {htmlAttributes, helpers, bodyContent} = content;

  res.write(`
        <!DOCTYPE html>
        <html ${helpers.attrs({...htmlAttributes})}>
        <head>
            ${renderHeadContent(content)}
        </head>
        <body ${helpers.attrs(bodyContent.attributes)}>
            ${renderBodyContent(content)}
    `);

  const data = await getUserData();

  res.write(`
            ${content.renderHelpers.renderInlineScript(`
                window.__DATA__ = ${htmlescape(data)};
            `)}
        </body>
        </html>
    `);
  res.end();
});

app.listen(3000);
```

# @gravity-ui/date-utils

Helpers for managing Date and Time.

## Install

```shell
npm i @gravity-ui/date-utils
```

## Usage

```typescript
import {dateTimeParse, dateTime} from '@gravity-ui/date-utils';

// Current date: 2021-08-07T12:10:00
// User's time zone: Europe/Istanbul

const FORMAT = 'YYYY-MM-DDTHH:mm:ssZ';

// parse absolute date
dateTimeParse({year: 2021, month: 7, day: 7})?.format(FORMAT); // "2021-08-07T00:00:00+03:00"
dateTimeParse([2021, 7, 7])?.format(FORMAT); // "2021-08-07T00:00:00+03:00"
dateTimeParse('2021-08-07')?.format(FORMAT); // "2021-08-07T00:00:00+03:00"
dateTimeParse(1621708204063)?.format(FORMAT); // "2021-05-22T21:30:04+03:00"
dateTimeParse('')?.format(FORMAT); // undefined
dateTimeParse('incorrect-date')?.format(FORMAT); // undefined

// parse relative date
dateTimeParse('now')?.format(FORMAT); // "2021-08-07T12:10:00+03:00"
dateTimeParse('now-1d')?.format(FORMAT); // "2021-08-06T12:10:00+03:00"
dateTimeParse('now-1d+1M')?.format(FORMAT); // "2021-09-06T12:10:00+03:00"
dateTimeParse('now/d')?.format(FORMAT); // "2021-08-07T00:00:00+03:00"
dateTimeParse('now+1d/d')?.format(FORMAT); // "2021-08-08T00:00:00+03:00"
dateTimeParse('now-1f')?.format(FORMAT); // undefined

// create dateTime
dateTime().format(FORMAT); // "2021-08-07T12:10:00+03:00"
dateTime({input: '2021-08-07'}).format(FORMAT); // "2021-08-07T00:00:00+03:00"
dateTime({input: '2021-08-07', format: 'YYYY-MM-DD'}).format(FORMAT); // "2021-08-07T00:00:00+03:00"
dateTime({timeZone: 'Asia/Tokyo'}).format(FORMAT); // "2021-08-07T18:10:00+09:00
dateTime({input: ''}).format(FORMAT); // "Invalid Date"
dateTime({input: '2021-08', format: 'YYYY-MM-DD'}).format(FORMAT); // "Invalid Date"
```

## Settings

```typescript
import {settings} from '@gravity-ui/date-utils';

// Locales management
settings.getLocale(); // default locale "en"
settings.loadLocale('de').then(() => {
  settings.setLocale('de');
  settings.getLocale(); // "de"
});

// Customization
settings.updateLocale({weekStart: 0}); // change first day of week
```

# Getting Started

## Installation

You can install the Date Utils library using npm or yarn:

```bash
# Using npm
npm install @gravity-ui/date-utils

# Using yarn
yarn add @gravity-ui/date-utils
```

## Basic Usage

### Importing

You can import the specific functions you need:

```typescript
import {dateTimeParse, dateTime, settings} from '@gravity-ui/date-utils';
```

### Parsing Dates

The `dateTimeParse` function is the main entry point for parsing dates. It can parse dates from various formats:

```typescript
import {dateTimeParse} from '@gravity-ui/date-utils';

// Parse from object
const date1 = dateTimeParse({year: 2021, month: 7, day: 7});

// Parse from array [year, month, day]
const date2 = dateTimeParse([2021, 7, 7]);

// Parse from string
const date3 = dateTimeParse('2021-08-07');

// Parse from timestamp (milliseconds)
const date4 = dateTimeParse(1621708204063);

// Parse relative dates
const now = dateTimeParse('now');
const yesterday = dateTimeParse('now-1d');
const nextMonth = dateTimeParse('now+1M');
const startOfDay = dateTimeParse('now/d');
const startOfNextDay = dateTimeParse('now+1d/d');
```

### Creating DateTime Objects

The `dateTime` function creates a DateTime object:

```typescript
import {dateTime} from '@gravity-ui/date-utils';

// Current date and time
const now = dateTime();

// From a string
const date1 = dateTime({input: '2021-08-07'});

// With a specific format
const date2 = dateTime({input: '2021-08-07', format: 'YYYY-MM-DD'});

// With a specific time zone
const date3 = dateTime({timeZone: 'Asia/Tokyo'});
```

### Formatting Dates

DateTime objects have a `format` method for formatting dates:

```typescript
import {dateTime} from '@gravity-ui/date-utils';

const date = dateTime({input: '2021-08-07T12:30:45'});

// Basic formatting
console.log(date.format('YYYY-MM-DD')); // '2021-08-07'
console.log(date.format('DD/MM/YYYY')); // '07/08/2021'
console.log(date.format('MMMM D, YYYY')); // 'August 7, 2021'
console.log(date.format('HH:mm:ss')); // '12:30:45'

// ISO string
console.log(date.toISOString()); // '2021-08-07T12:30:45.000Z'
```

### Manipulating Dates

DateTime objects provide methods for manipulating dates:

```typescript
import {dateTime} from '@gravity-ui/date-utils';

const date = dateTime({input: '2021-08-07'});

// Adding time
const tomorrow = date.add(1, 'd');
const nextWeek = date.add(1, 'w');
const nextMonth = date.add(1, 'M');

// Subtracting time
const yesterday = date.subtract(1, 'd');
const lastWeek = date.subtract(1, 'w');
const lastMonth = date.subtract(1, 'M');

// Start/end of time periods
const startOfDay = date.startOf('day');
const endOfMonth = date.endOf('month');
```

### Working with Time Zones

DateTime objects provide methods for working with time zones:

```typescript
import {dateTime, getTimeZonesList, guessUserTimeZone} from '@gravity-ui/date-utils';

// Get the user's time zone
const userTimeZone = guessUserTimeZone();

// Get a list of all time zones
const timeZones = getTimeZonesList();

// Create a date in a specific time zone
const tokyoDate = dateTime({timeZone: 'Asia/Tokyo'});

// Convert to a different time zone
const newYorkDate = tokyoDate.timeZone('America/New_York');

// Get the time zone offset
console.log(tokyoDate.utcOffset()); // minutes
```

### Working with Relative Dates

The library provides support for parsing relative date expressions:

```typescript
import {dateTimeParse} from '@gravity-ui/date-utils';

// Current date and time
const now = dateTimeParse('now');

// 1 day ago
const yesterday = dateTimeParse('now-1d');

// 1 day ago + 1 month
const complexDate = dateTimeParse('now-1d+1M');

// Start of today
const startOfToday = dateTimeParse('now/d');

// Start of tomorrow
const startOfTomorrow = dateTimeParse('now+1d/d');
```

### Settings and Localization

The library provides settings for configuration and localization:

```typescript
import {settings} from '@gravity-ui/date-utils';

// Get current locale
const currentLocale = settings.getLocale(); // default is "en"

// Load and set a new locale
settings.loadLocale('de').then(() => {
  settings.setLocale('de');
});

// Customize locale settings
settings.updateLocale({weekStart: 0}); // change first day of week
```

## Next Steps

For more detailed information about the library's features and API, check out the [API documentation](./api/overview.md).

# Axios Wrapper
This library provides a convenient wrapper around Axios adding automatic cancelling of concurrent requests
to its features.

## Install

```shell
npm install --save-dev @gravity-ui/axios-wrapper
```

## HTTP API

### Constructor parameters

##### config [optional]
The configuration of an `axios` instance.

##### collector [optional]
The configuration of requests collector is an object:
```json
{
    "collectErrors": 10,
    "collectRequests": 10
}
```

### Basic methods
Wrapper provides http-methods `get`, `head`, `put`, `post`, `delete`.

Methods `get` and `head` have the signature `(url, params, options)`; `put`, `post`, while the `delete` method
has `(url, data, params, options)` signature.

The `params` argument stands for query string parameters while `options` is a request settings.

Currently 4 request settings are supported:
- `concurrentId (string)`: optional request id
- `collectRequest (bool)`: optional flag, telling if the request should be logger (default `true`)
- `requestConfig (object)`: optional config with the custom request parameters
- `headers (object)`: optional object with custom request headers.
- `timeout (number)`: optional request timeout
- `onDownloadProgress (function)`: optional callback for processing file download progress

### Headers
The `setDefaultHeader({name (string), value (string), methods (array)})` method allows to add a default
request header.

Arguments `name` and `value` are required, optional argument `methods` specified all methods which get those
default headers (by default all methods will get those headers).

### CSRF
The `setCSRFToken` method allows specifying CSRF-token, which will be added to all `put`, `post` and `delete`
requests.

### Concurrent requests
Sometimes it is better to cancel the request in flight if its results are no longer needed. To make this
happen, one should pass to request's `options` the `concurrentId` id. When the next request with the same
`concurrentId` occurs the previous request with that id will be cancelled.

One cancel a request manually as well by invoking the `cancelRequest(concurrentId)` method.

### Collecting requests
It is possible to set up requests collection into the local storage using the `collector` option. It stores
all requests and errors separately. The following `apiInstance` will keep 10 last requests (both successful
and not) and 10 last erroneous requests.
```javascript
const apiInstance = new API({
    collector: {
        collectErrors: 10,
        collectRequests: 10
    }
});
```

To obtain saved requests one have to invoke the `getCollectedRequests` method which returns the object
`{errors: [...], requests: [...]}`.

### Usage
The suggested usage is to subclass the base `AxiosWrapper` class:
```javascript
export class API extends AxiosWrapper {
    getProjects() {
        return this.get('/projects');
    }
    getSensors({project, selectors}) {
        return this.get(`/projects/${project}/sensors`, {selectors, pageSize: 200});
    }
    getNames({project, selectors}) {
        return this.get(`/projects/${project}/sensors/names`, {selectors});
    }
    getLabels({project, names, selectors}) {
        return this.get(`/projects/${project}/sensors/labels`, {names, selectors});
    }
}
```

When the `baseURL` parameter is passed into `axios` config, all requested pathnames will be appended to it.
```javascript
const apiInstance = new API({
    config: {
        baseURL: '/api/v2'
    }
});
```

# auto-generate-translation-message-id

Проверяет наличие идентификатора в объекте перевода и добавляет его при отсутствии.

## Подключение

Вот пример того, как настроить это правило:

```javascript
module.exports = {
    "@gravity-ui/eslint-plugin-i18n/auto-generate-translation-message-id": [
        "error",
        {
            namespaceMatchers: [/src\/pages\/([^/]+)/, /src\/([^/]+)/],
        },
    ]
}
```

## Опции

- `namespaceMatchers`: Массив регулярных выражений для сопоставления пространства имен сообщения. Это используется для генерации уникального идентификатора для каждого сообщения на основе его пространства имен.

- `idName`: Имя идентификатора. Значение по умолчанию: `id`.

- `generateId`: Функция для генерации идентификаторов.

- `maxValidLength`: Максимальная валидная длина генерируемого идентификатора. Если длина идентификатора превышает это значение, то будет показываться ошибка с необходимостью изменить регулярное выражение в namespaceMatchers, используемое для генерации, либо функцию generateId, либо использовать кастомный идентификатор. Значение по умолчанию: `256`.

- `invalidCharsPattern`: Регулярное выражение для определения запрещенных символов, которые будут заменены значением из `invalidCharsReplacement` или результатом выполнения функции `invalidCharsReplacer`, если она задана. Значение по умолчанию: `/[^\w-_.:/]/g`.

- `invalidCharsReplacement`: Значение, которое будет использоваться для замены запрещенных символов из `invalidCharsPattern`. Значение по умолчанию: `_`.

> **Примечание:** При генерации идентификатора, точки (`.`) в ключе объекта переводов заменяются на нижнее подчеркивание (`_`). Например, если ключ объекта переводов `button.label`, то в идентификаторе он будет представлен как `button_label`.

- `invalidCharsReplacer`: Функция для замены запрещенных символов. Используется в качестве колбэка в `replaceAll(invalidCharsPattern, invalidCharsReplacer)`. Имеет следующую сигнатуру: [MDN Reference](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/String/replace#specifying_a_function_as_the_replacement)

- `memberExpressions`: Массив выражений для обозначения переводов, для которых должно применятся правило. Например, если вы хотите применить правило к `intl.createMessages({...})`, вы должны указать `[{member: 'intl', property: 'createMessages'}]`

## Примеры работы правила

Пример **некорректного** кода для этого правила:

```js
// ⛔️ Отсутствует идентификатор у объекта перевода "open"
intl.createMessages({
    open: {
        en: "Open",
        meta: {
            description: ""
        }
    }
})
```

Пример **корректного** кода для этого правила:

```js
// ✅ Есть идентификатор у всех переводов
intl.createMessages({
    open: {
        en: "Open",
        meta: {
            id: 'LandingPage.dST4FxmGt7j9QxJEomNPXf',
            description: ""
        }
    }
})
```

# detect-incorrect-calls

Правило делает следующее:

1. Проверяет, что в декларацию i18n-хелпера через bind передается литерал.

    ```js
    import i18n from 'ui/utils/i18n';

    // ✅ Разрешено использовать литералы
    const i18nK = i18n.bind(null, 'somekeyset');
    // ⛔️ Запрещено использовать переменные
    const i18nK = i18n.bind(null, SOME_KEYSET_VARIABLE);
    // ⛔️ Запрещено использовать шаблонные строки
    const i18nK = i18n.bind(null, `somekeyset`);
    ```

2. Проверяет названия деклараций i18n-хелперов (должны начинаться с префикса `i18n`):

    ```js
    import i18n from 'ui/utils/i18n';

    // ✅
    const i18nK = i18n.bind(null, 'somekeyset');
    const i18nSomeKeyset = i18n.bind(null, 'somekeyset');

    // ⛔️
    const ki18n = i18n.bind(null, 'somekeyset');
    const someDevI18n = i18n.bind(null, 'somekeyset');
    ```

3. Проверяет, что i18n-хелпер назначается переменной:

    ```js
    import i18n from 'ui/utils/i18n';

    // ✅
    const i18nK = i18n.bind(null, 'somekeyset');

    // ⛔️
    const i18nHelpers = {
        i18nK: i18n.bind(null, 'somekeyset'),
    };
    ```

4. Проверяет чтобы вызываемые идентификаторы были объявлены в текущем файле (не касается глобального i18n):

    ```js
    import i18n from 'ui/utils/i18n';

    // ✅
    const i18nK = i18n.bind(null, 'somekeyset');
    console.log(i18nK('hello'));
    console.log(i18n('somekeyset', 'hello'))

    // ⛔️
    import {i18nK} from '../someModule';
    console.log(i18nK('hello'));
    ```

5. Проверяет чтобы в вызове i18n был литерал:

    ```js
    import i18n from 'ui/utils/i18n';

    const i18nK = i18n.bind(null, 'somekeyset');

    // ⛔️
    const SOME_KEY = 'label_active';
    console.log(i18nK(SOME_KEY));
    console.log(i18nK(`label_status-${instance.status}`));
    console.log(i18n('somekeyset', `label_status-${instance.status}`));

    // ✅
    console.log(i18nK('hello'));
    console.log(i18n('somekeyset', 'hello'));

    const instanceStatusNames: Record<InstanceStatus, string> = {
        [InstanceStatus.Running]: i18nK('label_status-running'),
        [InstanceStatus.Active]: i18nK('label_status-active'),
        [InstanceStatus.Terminated]: i18nK('label_status-terminated'),
    };
    console.log(instanceStatusNames[instance.status]);
    ```

6. Проверяет чтобы в вызове i18n параметры передавались как ObjectExpression:

    ```js
    import i18n from 'ui/utils/i18n';

    const i18nK = i18n.bind(null, 'somekeyset');

    // ✅
    console.log(i18nK('hello', {param: '123'}));
    console.log(i18n('somekeyset', 'hello', {param: '123'}));

    // ⛔️
    const params = {param: '123'};
    console.log(i18nK('hello', params));
    console.log(i18n('somekeyset', 'hello', params));
    ```

7. Запрещает экспорты i18n-хелперов:

    ```js
    import i18n from 'ui/utils/i18n';

    // ⛔️
    export const i18nK = i18n.bind(null, 'somekeyset');
    export default i18n.bind(null, 'somekeyset');
    export default i18nK;
    export {
        i18nK,
    };
    ```

# restrict-i18n-imports

Запрещает импорт файлов с текстами (`i18n.ts`) из директорий других уровней.

## Подключение

Пример подключения правила:

```javascript
module.exports = {
    "@gravity-ui/eslint-plugin-i18n/restrict-i18n-imports": [
        "error",
        {
            exclusions: {
                aliases: ['@shared/i18n'],
                filePathsMatchers: [/shared\/i18n\/*/],
            },
        },
    ]
}
```

## Опции

- `exclusions.aliases`: Массив алиасов импортов, которые должны быть исключены из проверки (будут являться валидными импортами).

- `exclusions.filePathsMatchers`: Массив регулярных выражений для сопоставления путей файлов, которые должны быть исключены из проверки (будут являться валидными импортами).

## Примеры работы правила

Пример **некорректного** кода для этого правила:

```js
// ⛔️ Импорт переводов с другого уровня вложенности
import {t} from '../i18n'

// ⛔️ Импорт переводов с другого уровня вложенности
import {t} from './utils/i18n'
```

Пример **корректного** кода для этого правила:

```js
// ✅ Импорт переводов с того же уровня вложенности
import {t} from './i18n'

// ✅ Импорт переводов, используя переданный алиас (exclusions.aliases)
import {t} from '@shared/i18n'

// ✅ Импорт переводов, используя путь, который соответствует
// одному из переданных регулярных выражений (exclusions.filePathsMatchers)
import {t} from '../shared/i18n'
```

# @gravity-ui/i18n-babel-plugin

Babel plugin for optimizing translation file delivery.

If you're not using babel, then [i18n-optimize-plugin](../i18n-optimize-plugin/README.md) would be suitable for you.

*Transforms `i18n.ts` files:*

- Removes meta from messages (id, description, etc.)
- Converts markdown to html (when `meta.markdown === true`)
- Applies typograf rules to key content

*TODO:*

- Validates syntax according to ICU MessageFormat
- Compiles ICU MessageFormat to AST
- Replaces original keys with hashes (allows reducing key length)

## Usage

Install the plugin:

```bash
npm install @gravity-ui/i18n-babel-plugin --save-dev
```

Connect the plugin to the build. Example if you're using `app-builder`:

```ts
import {defineConfig} from '@gravity-ui/app-builder';

export default defineConfig({
    client: {
        babel: (config) => {
            const plugins = config.plugins ? [...config.plugins] : [];

            return {
                ...config,
                plugins: [
                    ...plugins,
                    require.resolve('@gravity-ui/i18n-babel-plugin')
                ],
            };
        }
    }
});
```

## Settings

### typograf

Allows configuring [typograf rules](https://github.com/typograf/typograf/blob/dev/docs/RULES.ru.md).

By default, uses [`DEFAULT_TYPOGRAF_CONFIG`](./src/typograf.ts) rules.

Example of customizing typograph rules:

```ts
plugins: [
    require.resolve('@gravity-ui/i18n-babel-plugin', {
        typograf: {
            enabled: ['common/nbsp/afterNumber', 'common/nbsp/afterParagraphMark'],
            disabled: ['common/symbols/cf', 'common/space/trimRight', 'common/space/trimLeft'],
        }
    })
],
```

Example of disabling typograph:

```ts
plugins: [
    require.resolve('@gravity-ui/i18n-babel-plugin', {
        typograf: false,
    })
],
```

### root

Allows limiting the plugin's scope. The plugin will not process files outside the specified scope.

Type: `string`.

Default: `src`.

# @gravity-ui/i18n-cli

- Provides i18n configuration for the project

- Provides the `i18n-cli` command for managing language files in the project.


## Project Setup

1. **Install the package:**

    ```bash
    npm i -D @gravity-ui/i18n-cli
    ```

2. **Createthe config file `i18n.config.ts` in the project root:**

    ```ts
    import {defineConfig} from '@gravity-ui/i18n-cli/config';

    export default defineConfig({
        allowedLocales: ['ru', 'en', 'ru-kz', 'en-kz'] as const,
        fallbackLocales: {
            'ru-kz': 'ru',
            'en-kz': 'en',
        },
        defaultFallback: 'en',
        clientIntlModule: {
            path: 'src/shared/i18n/intl.ts',
            alias: '@shared/i18n',
        },
    });
    ```
3. **Import the config in the i18n library instance (i18n-react and i18n-node)**

    ```ts
    import {createIntl} from '@gravity-ui/i18n-react';
    import i18nConfig from '../../../i18n.config';

    const {allowedLocales, fallbackLocales, defaultFallback} = i18nConfig;

    export const intl = createIntl({
        allowedLocales,
        fallbackLocales,
        defaultFallback,
    });
    ```

## Commands

### `create-keys`

Checks the provided file/directory for calls to missing keys and adds them to the `i18n.ts` file.

#### Run for a single file

```bash
npx i18n-cli create-keys src/ui/SomeComponent/SomeComponent.tsx
```

#### Run for all files in a directory

```bash
npx i18n-cli create-keys src/ui/ComponentDirectory
```

### `find-unused`

Recursively search for unused keys starting from the specified directory.

#### Report on unused keys

```bash
npx i18n-cli find-unused src/ui/SomeComponent
```

#### Delete unused keys

```bash
npx i18n-cli find-unused -d src/ui/SomeComponent
```

## Configuration options

### allowedLocales

Type: `string[]`

Allowed locales in the project.

```ts
{
    allowedLocales: ['ru', 'en'] as const,
}
```

### fallbackLocales

Fallbacks for given locales. More details can be found in [i18n-core](../i18n-core/README.md).

### defaultFallback

Default fallback. Used if no higher priority fallback is found. More in [i18n-core](../i18n-core/README.md).

### clientIntlModule

Location of the library instance for the client-side [i18n-react](../i18n-react/README.md) in the project.

```ts
{
    clientIntlModule: {
        // Path to the module with intl library instance
        path: 'src/ui/shared/i18n.ts',

        // TypeScript alias of the module with intl library instance
        alias: '@shared/i18n';
    }
}
```

### serverIntlModule

Server-side library instance location [i18n-node](../i18n-node/README.md) in the project.

```ts
{
    serverIntlModule: {
        // Path to the module containing the intl library instance
        path: 'src/server/utils/i18n.ts',

        // TypeScript alias of the module containing the intl library instance
        alias: undefined,

        // Regular expressions that determine if a module belongs to the server-side
        pathMatchers: [/src\/server\/.+$/]
    }
}
```

# @gravity-ui/i18n-optimize-plugin


Plugin for optimizing translation file delivery. Can be used with webpack, rspack, and vite.

Under the hood, uses [`i18n-babel-plugin`](../i18n-babel-plugin/README.md).

*Transforms `i18n.ts` files:*

- Removes meta from messages (id, description, etc.)
- Converts markdown to html (when `meta.markdown === true`)
- Applies typograf rules to key content
- Creates per-locale chunks and optimizes their runtime loading

*TODO:*

- Validates syntax according to ICU MessageFormat
- Compiles ICU MessageFormat to AST
- Replaces original keys with hashes (allows reducing key length)

## Usage

Install the plugin:

```bash
npm install @gravity-ui/i18n-optimize-plugin --save-dev
```

Connect the plugin to the build. Example if you're using `app-builder` with `rspack`:

```ts
import {defineConfig} from '@gravity-ui/app-builder';
import applyI18nOptimizePlugin from '@gravity-ui/i18n-optimize-plugin/rspack';

export default defineConfig({
    client: {
        rspack: (config) => {
            const plugins = config.plugins ? [...config.plugins] : [];

            return applyI18nOptimizePlugin(config);
        }
    },
});
```

Example if you're using `app-builder` with `webpack`:

```ts
import {defineConfig} from '@gravity-ui/app-builder';
import applyI18nOptimizePlugin from '@gravity-ui/i18n-optimize-plugin/webpack';

export default defineConfig({
    client: {
        webpack: (config) => {
            const plugins = config.plugins ? [...config.plugins] : [];

            return applyI18nOptimizePlugin(config);
        }
    },
});
```

## Settings

### typograf

Allows configuring [typograf rules](https://github.com/typograf/typograf/blob/dev/docs/RULES.ru.md).

By default, uses [`DEFAULT_TYPOGRAF_CONFIG`](./src/typograf.ts) rules.

Example of customizing typograf rules:

```ts
applyI18nOptimizePlugin(webpackConfig, {
    typograf: {
        enabled: ['common/nbsp/afterNumber', 'common/nbsp/afterParagraphMark'],
        disabled: ['common/symbols/cf', 'common/space/trimRight', 'common/space/trimLeft'],
    }
})
```

Example of disabling typograf:

```ts
applyI18nOptimizePlugin(webpackConfig, {
    typograf: false,
})
```

### optimizeLocaleChunks

Optimizes chunk loading at runtime: only translations for the current language are loaded to the client.

Works only in production mode for webpack/rspack. Disabled by default (false).

#### How to enable?

1. For proper chunk loading, you need to define the `runtimeLanguageVariableName` variable with the current user language in window.

    For example, if you're using `core`, you can do this through `inlineScripts`:

    ```ts
    return res.renderLayout2({
        inlineScripts: [
            `window.I18N_LANG = "${userLanguage}";`,
            'window.YC = window.__DATA__;'
        ],
    })
    ```

    By default, `window.I18N_LANG` is used for `runtimeLanguageVariableName`.

1. Configure dynamic manifest depending on user language (production only).

    For example, when using `core` this can be done through middleware:

    ```ts
    import {createMiddleware, getDefaultManifestPath} from '@gravity-ui/ui-core-layout';

    export const layoutMiddleware = createMiddleware(({lang}) => {
        let manifestName = 'assets-manifest.json';

        if (process.env.NODE_ENV === 'production' && lang) {
            manifestName = `assets-manifest.${lang}.json`;
        }

        return getDefaultManifestPath(manifestName);
    });
    ```

1. Enable the `optimizeLocaleChunks` option in plugin settings.

1. Add the line `.compiled-locales*` to `.arcignore`.

#### Optimization Strategies

The `strategy` parameter determines how language chunks are formed:

- `by-module` (default) - separate language chunks are created for each `i18n.ts` module. This allows loading translations only for modules used on the page.

- `all-in-one` - creates a common chunk for each language containing all project translations. Suitable for small projects where translation volume is small.

- `custom` - custom strategy allowing you to define your own chunk naming logic through the `getChunkName` function.

#### Language Variable Configuration

The `runtimeLanguageVariableName` parameter allows specifying the variable name that stores the current language. By default, `window.I18N_LANG` is used.

Example of enabling optimization:

```ts
// Default by-module strategy
applyI18nOptimizePlugin(webpackConfig, {
    optimizeLocaleChunks: true,
})

// all-in-one strategy
applyI18nOptimizePlugin(webpackConfig, {
    optimizeLocaleChunks: {
        strategy: 'all-in-one',
    },
})

// Changing runtime variable that stores user language
applyI18nOptimizePlugin(webpackConfig, {
    optimizeLocaleChunks: {
        strategy: 'by-module',
        runtimeLanguageVariableName: 'window.USER_LANG',
    },
})
```

# @gravity-ui/i18n &middot; [![npm package](https://img.shields.io/npm/v/@gravity-ui/i18n)](https://www.npmjs.com/package/@gravity-ui/i18n) [![CI](https://img.shields.io/github/actions/workflow/status/gravity-ui/i18n/.github/workflows/ci.yml?branch=main&label=CI&logo=github)](https://github.com/gravity-ui/i18n/actions/workflows/ci.yml?query=branch:main)

## I18N utilities

Utilities in the I18N package are designed for internationalization of Gravity UI services.

### Install

`npm install --save @gravity-ui/i18n`

### API

#### constructor(options)

Accepts `options` object with optional `logger` that would be used for logging library warnings.

##### logger

Logger should have explicit `log` method with following signature:

 * `message` - string of message that would be logged
 * `options` - object of logging options:
   * `level` - level for logging message, always `'info'`
   * `logger` - where to log library messages
   * `extra` - additional options object, with a single `type` string, that is always `i18n`

### Use examples

#### `keysets/en.json`

```json
{
  "wizard": {
    "label_error-widget-no-access": "No access to the chart"
  }
}
```

#### `keysets/ru.json`

```json
{
  "wizard": {
    "label_error-widget-no-access": "Нет доступа к чарту"
  }
}
```

#### `index.js`

```js
const ru = require('./keysets/ru.json');
const en = require('./keysets/en.json');

const {I18N} = require('@gravity-ui/i18n');

const i18n = new I18N();
i18n.registerKeysets('ru', ru);
i18n.registerKeysets('en', en);

i18n.setLang('ru');
console.log(
    i18n.i18n('wizard', 'label_error-widget-no-access')
); // -> "Нет доступа к чарту"

i18n.setLang('en');
console.log(
    i18n.i18n('wizard', 'label_error-widget-no-access')
); // -> "No access to the chart

// Keyset allows for a simpler translations retrieval
const keyset = i18n.keyset('wizard');
console.log(
    keyset('label_error-widget-no-access')
); // -> "No access to the chart"


i18n.setLang('ru');
console.log(
    keyset('label_error-widget-no-access')
); // -> "Нет доступа к чарту"

// Checking if keyset has a key
if (i18n.has('wizard', 'label_error-widget-no-access')) {
    i18n.i18n('wizard', 'label_error-widget-no-access')
}
```

### Templating

The library supports templating. Templated variables are enclosed in double curly brackets, and the values are passed to the i18n function as a key-value dictionary:

#### `keysets.json`

```json
{
  "label_template": "No matches found for '{{inputValue}}' in '{{folderName}}'"
}
```

#### `index.js`

```js
i18n('label_template', {inputValue: 'something', folderName: 'somewhere'});  // => No matches found for "something" in "somewhere"
```

### Pluralization

Pluralization can be used for easy localization of keys that depend on numeric values. Current library uses [CLDR Plural Rules](https://unicode-org.github.io/cldr-staging/charts/latest/supplemental/language_plural_rules.html) via [Intl.PluralRules API](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Intl/PluralRules).

You may need to [polyfill](https://github.com/eemeli/intl-pluralrules) the [Intl.Plural Rules API](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Intl/PluralRules) if it is not available in the browser.

There are 6 plural forms (see [resolvedOptions](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Intl/PluralRules/resolvedOptions)):

- zero (also will be used when count = 0 even if the form is not supported in the language)
- one (singular)
- two (dual)
- few (paucal)
- many (also used for fractions if they have a separate class)
- other (required form for all languages — general plural form — also used if the language only has a single form)

#### Example of `keysets.json` with plural key

```json
{
  "label_seconds": {
    "one": "{{count}} second is left",
    "other":"{{count}} seconds are left",
    "zero": "No time left"
  }
}
```

#### Usage in JS

```js
i18n('label_seconds', {count: 1});  // => 1 second
i18n('label_seconds', {count: 3});  // => 3 seconds
i18n('label_seconds', {count: 7});  // => 7 seconds
i18n('label_seconds', {count: 10}); // => 10 seconds
i18n('label_seconds', {count: 0});  // => No time left
```

#### [Deprecated] Old plurals format

Old format will be removed in v2.

```json
{
  "label_seconds": ["{{count}} second is left", "{{count}} seconds are left", "{{count}} seconds are left", "No time left"]
}
```

A pluralized key contains 4 values, each |corresponding to a `PluralForm` enum value. The enum values are: `One`, `Few`, `Many`, and `None`, respectively. Template variable name for pluralization is `count`.

#### [Deprecated] Custom pluralization

Since every language has its own way of pluralization, the library provides a method to configure the rules for any chosen language.

The configuration function accepts an object with languages as keys, and pluralization functions as values.

A pluralization function accepts a number and the `PluralForm` enum, and is expected to return one of the enum values depending on the provided number.

```js
const {I18N} = require('@gravity-ui/i18n');

const i18n = new I18N();

i18n.configurePluralization({
  en: (count, pluralForms) => {
    if (!count) return pluralForms.None;
    if (count === 1) return pluralForms.One;
    return pluralForms.Many;
  },
});
```

#### [Deprecated] Provided pluralization rulesets

The two languages supported out of the box are English and Russian.

##### English

Language key: `en`.
* `One` corresponds to 1 and -1.
* `Few` is not used.
* `Many` corresponds to any other number, except 0.
* `None` corresponds to 0.

##### Russian

Language key: `ru`.
* `One` corresponds to any number ending in 1, except ±11.
* `Few` corresponds to any number ending in 2, 3 or 4, except ±12, ±13 and ±14.
* `Many` corresponds to any other number, except 0.
* `None` corresponds to 0.

##### Default

The English ruleset is used by default, for any language without a configured pluralization function.

### Nesting

